import{_ as e}from"./chunks/v2-setup.BzByyTgt.js";import{_ as r,o as i,c as o,ag as s}from"./chunks/framework.CvgP6Fyv.js";const a="/images/git-remote-guide/gitee-1.png",n="/images/git-remote-guide/gitee-2.png",g="/images/git-remote-guide/gitee-3.png",l="/images/git-remote-guide/gitee-4.png",p="/images/git-remote-guide/gitee-5.png",G=JSON.parse('{"title":"Gitee 配置指南","description":"","frontmatter":{},"headers":[],"relativePath":"guide/gitee.md","filePath":"guide/gitee.md","lastUpdated":1776962252000}'),d={name:"guide/gitee.md"};function c(h,t,m,_,u,S){return i(),o("div",null,[...t[0]||(t[0]=[s('<h1 id="gitee-配置指南" tabindex="-1">Gitee 配置指南 <a class="header-anchor" href="#gitee-配置指南" aria-label="Permalink to &quot;Gitee 配置指南&quot;">​</a></h1><p>本文以 Gitee 为例，介绍从创建仓库到完成同步的完整流程。</p><h2 id="_1-创建远程仓库" tabindex="-1">1. 创建远程仓库 <a class="header-anchor" href="#_1-创建远程仓库" aria-label="Permalink to &quot;1. 创建远程仓库&quot;">​</a></h2><ol><li><p>访问 <a href="https://gitee.com/" target="_blank" rel="noopener noreferrer">Gitee</a> 注册并登录。</p></li><li><p>点击右上角「<strong>+</strong>」→「<strong>新建仓库</strong>」</p><p><img src="'+a+'" alt="新建仓库"></p></li><li><p>填写仓库名称（如 <code>my-sts-mods</code>），选择开源或私有，点击「<strong>创建</strong>」。</p><ul><li><strong>开源仓库</strong> — 所有人可见，不限制协作人数。队友无需注册 Gitee 账号即可拉取，但上传仍需要账号和认证。</li><li><strong>私有仓库</strong> — 仅被邀请的人可见，免费账号最多 5 名协作者。所有队友都必须注册账号并被邀请后才能使用。</li></ul><p><img src="'+n+'" alt="仓库信息"></p></li><li><p>创建成功后进入仓库主页，点击「<strong>HTTPS</strong>」，复制仓库地址。</p><p><img src="'+g+'" alt="复制链接"></p></li></ol><h2 id="_2-配置-sync-the-spire" tabindex="-1">2. 配置 Sync the Spire <a class="header-anchor" href="#_2-配置-sync-the-spire" aria-label="Permalink to &quot;2. 配置 Sync the Spire&quot;">​</a></h2><h3 id="认证方式" tabindex="-1">认证方式 <a class="header-anchor" href="#认证方式" aria-label="Permalink to &quot;认证方式&quot;">​</a></h3><table tabindex="0"><thead><tr><th>方式</th><th>说明</th></tr></thead><tbody><tr><td><strong>免密</strong>（推荐）</td><td>需要认证时系统弹出 Git 凭据窗口，输入 Gitee 账号密码即可，无需额外配置</td></tr><tr><td><strong>SSH</strong></td><td>如果你已配置 SSH 密钥，也可以使用 SSH 方式连接</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">Gitee 不支持 HTTPS 认证</p><p>请勿在 Sync the Spire 中对 Gitee 仓库选择「HTTPS」鉴权方式，Gitee 不兼容该方式。请使用「<strong>免密</strong>」。</p></div><ol start="5"><li><p>打开 Sync the Spire，<a href="/guide/workspace">创建一个工作区</a>后进入配置页面。将复制的仓库地址粘贴到「远程仓库 URL」输入框，填写昵称，认证方式选「<strong>免密</strong>」。</p></li><li><p>填写或自动查找游戏路径和存档路径，点击「<strong>保存并初始化</strong>」。</p><ul><li><strong>开源仓库</strong>：初始化时可直接拉取，首次<strong>上传</strong>时会弹出 Git 凭据窗口，输入 Gitee 账号密码即可。</li><li><strong>私有仓库</strong>：初始化<strong>拉取时</strong>就会弹出 Git 凭据窗口，输入账号密码完成认证。</li></ul><p><img src="'+e+'" alt="配置页"></p></li></ol><h2 id="_3-邀请队友" tabindex="-1">3. 邀请队友 <a class="header-anchor" href="#_3-邀请队友" aria-label="Permalink to &quot;3. 邀请队友&quot;">​</a></h2><p>推荐每位朋友各自注册 Gitee 账号，在仓库中添加为协作者，各用各的账号。</p><ol start="7"><li><p>进入仓库「<strong>管理</strong>」→ 左侧「<strong>仓库成员管理</strong>」→「<strong>添加成员</strong>」。</p><p><img src="'+l+'" alt="添加成员"></p></li><li><p>权限选「<strong>开发者</strong>」，将邀请链接发给朋友。朋友接受邀请后，再把<strong>仓库地址</strong>一并发给他们。</p><p><img src="'+p+'" alt="协作者邀请"></p></li><li><p>朋友在 Sync the Spire 中创建工作区后，填入同样的仓库地址，认证方式同样选「<strong>免密</strong>」，初始化完成后即可同步你的 Mod 配置。</p></li></ol>',12)])])}const P=r(d,[["render",c]]);export{G as __pageData,P as default};
